// Render inline SVG from icon key
export function IconSVG( { name, width = 24, height = 24 } ) {
	const icon = ICONS[ name ];
	if ( ! icon ) return null;
	return (
		<svg
			xmlns="http://www.w3.org/2000/svg"
			width={ width }
			height={ height }
			fill="currentColor"
			viewBox="0 0 16 16"
			aria-hidden="true"
		>
			<path d={ icon.path } />
		</svg>
	);
}
